class Solution {
    public int minimizeTheDifference(int[][] mat, int target) {
        int m = mat.length, n = mat[0].length;
        int[] dp = new int[4901], new_dp = new int[4901];
        dp[0] = 1;
        for (int i = 0; i < m; ++i) {
            Arrays.fill(new_dp, 0);
            for (int j = 0; j < n; ++j) {
                for (int k = 0; k + mat[i][j] < 4901; ++k) {
                    new_dp[k + mat[i][j]] |= dp[k];
                }
            }
            int[] temp = dp;
            dp = new_dp;
            new_dp = temp;
        }
        for (int i = 0; i < 4901; ++i) {
            if (dp[i] > 0) return Math.abs(target - i);
        }
        return Integer.MAX_VALUE;
    }
}
